arguments.file_text:
@page "/catalog"
@using sv_219b39efac444326a8a519145a06a578.Components.Catalog
@using sv_219b39efac444326a8a519145a06a578.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

<div class="d-flex gap-3">
    <div class="catalog-sidebar-container" style="flex: 0 0 25%; max-width: 25%;">
        <CatalogSidebar Categories="_categories" OnFilterApplied="HandleFilterApplied" />
    </div>

    <div class="catalog-main" style="flex: 1; min-width: 0;">
        @if (_error is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @_error
                <button class="btn btn-sm btn-outline-danger ms-2" @onclick="RetryLoad">Retry</button>
            </div>
        }
        else if (_loading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (_result is not null && _result.Items.Count == 0)
        {
            <div class="alert alert-info" role="alert">
                No products match your filters. Try adjusting your search criteria.
            </div>
        }
        else if (_result is not null)
        {
